ype": "secondary", "margin-top": "30px", "margin-left": "30px", "margin-right": "20px", "border-top-left-radius": "20px", "border-top-right-radius": "20px", "border-bottom-left-radius": "20px", "border-bottom-right-radius": "20px"}, "pageId": "f4cfcf9a-9439-4db2-aa60-9680d7c94acc", "childrens": [], "childrenIds": [], "application_id": "e5ea6ef3-f467-402c-bacf-199d68bdc63d", "component_type": "button_input"}], "childrenIds": ["9b4ac419-194e-4289-a46f-1794f6e148e6", "20f56db0-4535-4a79-a7d1-5be8e2ab810c"], "application_id": "e5ea6ef3-f467-402c-bacf-199d68bdc63d", "component_type": "vertical-container-block"}, {"name": "application-container_cuyv_6a1h", "uuid": "5028416f-a923-4634-89af-fb8f05b1249d", "style": {"margin-top": "30px", "margin-left": "20px", "padding-left": "0px"}, "pageId": "f4cfcf9a-9439-4db2-aa60-9680d7c94acc", "childrens": [{"name": "Collection_2540_ulq4_c5zu", "uuid": "897f6adc-5ef1-4f97-b202-8b8ddad7c044", "event": {"onInit": "// Existing load_functions method\\nVars.studio_load_applications = () => {\\n    fetch('/api/applications', {\\n        method: 'GET',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            throw new Error(`HTTP error! status: ${response.status}`);\\n        }  \\n        return response.json();\\n    })\\n    .then(data => {\\n        Vars.studio_applications = [...(data || [])];\\n        setTimeout(()=>{\\nVars.studio_applications = [...(data || [])];\\n        },0)\\n        return data;\\n    })\\n    .catch(error => {\\n        console.error('Error fetching functions:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n\\n\\nVars.create_new_app = () => {\\n    return fetch('/api/applications', {\\n        method: 'POST',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n        body: JSON.stringify({}),\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            return response.json().then(errData => {\\n                const errorMessage = errData.message || `HTTP error! status: ${response.status}`;\\n                throw new Error(errorMessage);\\n            });\\n        }\\n        return response.json();\\n    })\\n    .then(createdFunction => {\\n        Vars.studio_load_applications();\\n    })\\n    .catch(error => {\\n        console.error('Error creating function:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n\\n\\n\\nVars.delete_app = (uuid) => {\\n    return fetch(`/api/applications/${uuid}`, {\\n        method: 'DELETE',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n        body: JSON.stringify({}),\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            return response.json().then(errData => {\\n                const errorMessage = errData.message || `HTTP error! status: ${response.status}`;\\n                throw new Error(errorMessage);\\n            });\\n        }\\n        return response.json();\\n    })\\n    .then(createdFunction => {\\n        Vars.studio_load_applications();\\n    })\\n    .catch(error => {\\n        console.error('Error creating function:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n\\nVars.studio_load_applications();\\n// New create_function method\\nVars.create_function = (newFunctionData) => {\\n    return fetch('/api/v1/functions', {\\n        method: 'POST',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n        body: JSON.stringify(newFunctionData),\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            return response.json().then(errData => {\\n                const errorMessage = errData.message || `HTTP error! status: ${response.status}`;\\n                throw new Error(errorMessage);\\n            });\\n        }\\n        return response.json();\\n    })\\n    .then(createdFunction => {\\n        Vars.studio_functions.push(createdFunction);\\n        return createdFunction;\\n    })\\n    .catch(error => {\\n        console.error('Error creating function:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n"}, "input": {"data": {"type": "handler", "value": "return Vars.studio_applications;"}, "direction": {"type": "string", "value": "horizontal"}}, "style": {"--columns": "4"}, "pageId": "f4cfcf9a-9439-4db2-aa60-9680d7c94acc", "childrens": [{"name": "vertical-container-block_4563_evj7_ksjb", "uuid": "863ac94b-3cf9-48ec-9129-55154cd59cd9", "event": {"onClick": "NavigateToUrl(\\"/app/studio/\\"+Item.uuid)"}, "style": {"gap": "0px", "width": "200px", "cursor": "pointer", "height": "200px", "display": "flex", "margin-left": "10px", "margin-right": "10px", "margin-bottom": "20px", "justify-content": "center", "--container-bg-color": "#e6e6e6", "border-top-left-radius": "20px", "border-top-right-radius": "20px", "--container-dark-bg-color": "#424242", "border-bottom-left-radius": "20px", "border-bottom-right-radius": "20px"}, "pageId": "f4cfcf9a-9439-4db2-aa60-9680d7c94acc", "childrens": [{"name": "text_label_8027_551s_hdfe", "uuid": "351ac00d-bb4d-4086-a83f-f8adc41579fc", "input": {"value": {"type": "handler", "value": "Vars.studio_applications;\\nreturn Item.name;"}, "height": {"type": "string", "value": "auto"}}, "style": {"height": "auto", "fontSize": "18px", "margin-top": "10px", "margin-left": "0px"}, "pageId": "f4cfcf9a-9439-4db2-aa60-9680d7c94acc", "childrens": [], "childrenIds": [], "application_id": "e5ea6ef3-f467-402c-bacf-199d68bdc63d", "component_type": "text_label"}, {"name": "vertical-container-block_9815_cbug_xs38", "uuid": "73dcb1e0-0