cations', {\\n        method: 'GET',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            throw new Error(`HTTP error! status: ${response.status}`);\\n        }  \\n        return response.json();\\n    })\\n    .then(data => {\\n        Vars.studio_applications = [...(data || [])];\\n        setTimeout(()=>{\\nVars.studio_applications = [...(data || [])];\\n        },0)\\n        return data;\\n    })\\n    .catch(error => {\\n        console.error('Error fetching functions:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n\\n\\nVars.create_new_app = () => {\\n    return fetch('/api/applications', {\\n        method: 'POST',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n        body: JSON.stringify({}),\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            return response.json().then(errData => {\\n                const errorMessage = errData.message || `HTTP error! status: ${response.status}`;\\n                throw new Error(errorMessage);\\n            });\\n        }\\n        return response.json();\\n    })\\n    .then(createdFunction => {\\n        Vars.studio_load_applications();\\n    })\\n    .catch(error => {\\n        console.error('Error creating function:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n\\n\\n\\nVars.delete_app = (uuid) => {\\n    return fetch(`/api/applications/${uuid}`, {\\n        method: 'DELETE',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n        body: JSON.stringify({}),\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            return response.json().then(errData => {\\n                const errorMessage = errData.message || `HTTP error! status: ${response.status}`;\\n                throw new Error(errorMessage);\\n            });\\n        }\\n        return response.json();\\n    })\\n    .then(createdFunction => {\\n        Vars.studio_load_applications();\\n    })\\n    .catch(error => {\\n        console.error('Error creating function:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n\\nVars.studio_load_applications();\\n// New create_function method\\nVars.create_function = (newFunctionData) => {\\n    return fetch('/api/v1/functions', {\\n        method: 'POST',\\n        headers: {\\n            'Content-Type': 'application/json',\\n        },\\n        body: JSON.stringify(newFunctionData),\\n    })\\n    .then(response => {\\n        if (!response.ok) {\\n            // Handle non-OK response\\n            return response.json().then(errData => {\\n                const errorMessage = errData.message || `HTTP error! status: ${response.status}`;\\n                throw new Error(errorMessage);\\n            });\\n        }\\n        return response.json();\\n    })\\n    .then(createdFunction => {\\n        Vars.studio_functions.push(createdFunction);\\n        return createdFunction;\\n    })\\n    .catch(error => {\\n        console.error('Error creating function:', error);\\n        throw error; // Re-throw the error so the caller can handle it\\n    });\\n};\\n"}, "input": {"data": {"type": "handler", "value": "return Vars.studio_applications;"}, "direction": {"type": "string", "value": "horizontal"}}, "style": {"--columns": "4"}, "pageId": "f4cfcf9a-9439-4db2-aa60-9680d7c94acc", "childrens": [{"name": "vertical-container-block_4563_evj7_ksjb", "uuid": "863ac94b-3cf9-48ec-9129-55154cd59cd9", "event": {"onClick": "NavigateToUrl(\\"/app/studio/\\"+Item.uuid)"}, "style": {"gap": "0px", "width": "200px", "cursor": "pointer", "height": "200px", "display": "flex", "margin-left":